patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index 8d5866e98a8e..baa008abd3ea 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -185,6 +185,36 @@ static Value *foldMulShl1(BinaryOperator &Mul, bool CommuteOperands,
   return nullptr;
 }

+// fold mul (select C, A, B), (select C, B, A) -> mul A, B
+// This happens when two selects with the same condition but swapped arms
+// are multiplied - the result is always A * B regardless of condition.
+static Value *foldMulSwappedSelects(BinaryOperator &I,
+                                    InstCombiner::BuilderTy &Builder) {
+  Value *Cond0, *A, *B;
+  Value *Cond1, *C, *D;
+  
+  // Match: mul (select C, A, B), (select C, B, A)
+  if (!match(I.getOperand(0),
+             m_Select(m_Value(Cond0), m_Value(A), m_Value(B))))
+    return nullptr;
+  
+  if (!match(I.getOperand(1),
+             m_Select(m_Value(Cond1), m_Value(C), m_Value(D))))
+    return nullptr;
+  
+  // Check that conditions are the same
+  if (Cond0 != Cond1)
+    return nullptr;
+  
+  // Check that arms are swapped: first select is (A, B), second is (B, A)
+  if (A != D || B != C)
+    return nullptr;
+  
+  // Result is always: mul A, B
+  return Builder.CreateMul(A, B);
+}
+
+
 static Value *takeLog2(IRBuilderBase &Builder, Value *Op, unsigned Depth,
                        bool AssumeNonZero, bool DoFold);

@@ -207,6 +237,21 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
   if (Value *V = foldUsingDistributiveLaws(I))
     return replaceInstUsesWith(I, V);

+  if (Value *V = foldMulSwappedSelects(I, Builder))
+    return replaceInstUsesWith(I, V);
+
+  if (SimplifyAssociativeOrCommutative(I))
+    return &I;
+
+  if (Instruction *X = foldVectorBinop(I))
+    return X;
+
+  if (Instruction *Phi = foldBinopWithPhiOperands(I))
+    return Phi;
+
+  if (Value *V = foldUsingDistributiveLaws(I))
+    return replaceInstUsesWith(I, V);
+
   Type *Ty = I.getType();
   const unsigned BitWidth = Ty->getScalarSizeInBits();
   const bool HasNSW = I.hasNoSignedWrap();

